1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using Microsoft.Extensions.ML;
4. 
5. var builder = WebApplication.CreateBuilder(args);
6. 
7. var mlContext = new MLContext(seed: 42);
8. 
9. // Load CSV data
10. var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
11. IDataView rawData = mlContext.Data.LoadFromTextFile<RawCustomerData>(dataPath, hasHeader: true, separatorChar: ',');
12. 
13. // Map "Yes"/"No" string to a boolean Label column
14. IDataView data = mlContext.Transforms.CustomMapping<RawCustomerData, LabelMapping>(
15.     (input, output) => output.Label = input.Churned == "Yes",
16.     contractName: null)
17.     .Fit(rawData)
18.     .Transform(rawData);
19. 
20. var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);
21. 
22. var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(RawCustomerData.Region))
23.     .Append(mlContext.Transforms.Concatenate("Features",
24.         nameof(RawCustomerData.Age),
25.         nameof(RawCustomerData.Income),
26.         "RegionEncoded",
27.         nameof(RawCustomerData.PurchaseHistory)))
28.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
29.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
30.         labelColumnName: "Label",
31.         featureColumnName: "Features"));
32. 
33. var model = pipeline.Fit(split.TrainSet);
34. 
35. var predictions = model.Transform(split.TestSet);
36. try
37. {
38.     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
39.     Console.WriteLine($"Model Metrics — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
40. }
41. catch (ArgumentOutOfRangeException)
42. {
43.     Console.WriteLine("Warning: Test set too small for reliable metrics. Add more data for proper evaluation.");
44.     var trainMetrics = mlContext.BinaryClassification.Evaluate(
45.         model.Transform(split.TrainSet), labelColumnName: "Label");
46.     Console.WriteLine($"Train Metrics (overfit estimate) — AUC: {trainMetrics.AreaUnderRocCurve:F4}, Accuracy: {trainMetrics.Accuracy:F4}");
47. }
48. 
49. // Save and register for prediction pooling
50. var modelPath = Path.Combine(AppContext.BaseDirectory, "ChurnModel.zip");
51. mlContext.Model.Save(model, data.Schema, modelPath);
52. builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
53.     .FromFile(modelName: "ChurnModel", filePath: modelPath, watchForChanges: false);
54. 
55. var app = builder.Build();
56. 
57. app.MapPost("/predict", (CustomerInput input,
58.     PredictionEnginePool<CustomerInput, ChurnPrediction> pool) =>
59. {
60.     var prediction = pool.Predict("ChurnModel", input);
61.     return Results.Ok(new
62.     {
63.         WillChurn = prediction.PredictedLabel,
64.         Confidence = prediction.Probability
65.     });
66. });
67. 
68. app.Run();
69. 
