 using Microsoft.ML;
 using Microsoft.ML.Data;
 using Microsoft.Extensions.ML;

 var builder = WebApplication.CreateBuilder(args);

 var mlContext = new MLContext(seed: 42);

 // Load CSV data
 var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
 IDataView rawData = mlContext.Data.LoadFromTextFile<RawCustomerData>(dataPath, hasHeader: true, separatorChar: ',');

 // Map "Yes"/"No" string to a boolean Label column
 IDataView data = mlContext.Transforms.CustomMapping<RawCustomerData, LabelMapping>(
     (input, output) => output.Label = input.Churned == "Yes",
     contractName: null)
     .Fit(rawData)
     .Transform(rawData);

 var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

 var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(RawCustomerData.Region))
     .Append(mlContext.Transforms.Concatenate("Features",
         nameof(RawCustomerData.Age),
         nameof(RawCustomerData.Income),
         "RegionEncoded",
         nameof(RawCustomerData.PurchaseHistory)))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
         labelColumnName: "Label",
         featureColumnName: "Features"));

 var model = pipeline.Fit(split.TrainSet);

 var predictions = model.Transform(split.TestSet);
 try
 {
     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
     Console.WriteLine($"Model Metrics — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
 }
 catch (ArgumentOutOfRangeException)
 {
     Console.WriteLine("Warning: Test set too small for reliable metrics. Add more data for proper evaluation.");
     var trainMetrics = mlContext.BinaryClassification.Evaluate(
         model.Transform(split.TrainSet), labelColumnName: "Label");
     Console.WriteLine($"Train Metrics (overfit estimate) — AUC: {trainMetrics.AreaUnderRocCurve:F4}, Accuracy: {trainMetrics.Accuracy:F4}");
 }

 // Save and register for prediction pooling
 var modelPath = Path.Combine(AppContext.BaseDirectory, "ChurnModel.zip");
 mlContext.Model.Save(model, data.Schema, modelPath);
 builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
     .FromFile(modelName: "ChurnModel", filePath: modelPath, watchForChanges: false);

 var app = builder.Build();

 app.MapPost("/predict", (CustomerInput input,
     PredictionEnginePool<CustomerInput, ChurnPrediction> pool) =>
 {
     var prediction = pool.Predict("ChurnModel", input);
     return Results.Ok(new
     {
         WillChurn = prediction.PredictedLabel,
         Confidence = prediction.Probability
     });
 });

 app.Run();

 // Schema for loading the CSV (includes the raw Churned string)
 public class RawCustomerData
 {
     [LoadColumn(0)]
     public float Age { get; set; }

     [LoadColumn(1)]
     public float Income { get; set; }

     [LoadColumn(2)]
     public string Region { get; set; } = "";

     [LoadColumn(3)]
     public float PurchaseHistory { get; set; }

     [LoadColumn(4)]
     public string Churned { get; set; } = "";
 }

 // Custom mapping output — converts "Yes"/"No" to bool
 public class LabelMapping
 {
     public bool Label { get; set; }
 }

 // Schema for prediction input (no label needed)
 public class CustomerInput
 {
     public float Age { get; set; }
     public float Income { get; set; }
     public string Region { get; set; } = "";
     public float PurchaseHistory { get; set; }
 }

 public class ChurnPrediction
 {
     [ColumnName("PredictedLabel")]
     public bool PredictedLabel { get; set; }

     public float Probability { get; set; }

     public float Score { get; set; }
 }

